self.addEventListener("install",e=>{e.waitUntil(caches.open("gabi-shell-v1").then(s=>s.addAll(["/","/dist/main.js","/dist/index.css"]))),self.skipWaiting()});self.addEventListener("activate",e=>{e.waitUntil(caches.keys().then(s=>Promise.all(s.filter(t=>t!=="gabi-shell-v1").map(t=>caches.delete(t))))),self.clients.claim()});self.addEventListener("fetch",e=>{new URL(e.request.url).pathname.startsWith("/api/")||e.respondWith(caches.match(e.request).then(t=>t||fetch(e.request)))});
